#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long powmod(long long a, long long b) {
    long long res = 1;
    while (b > 0) {
        if (b & 1)
            res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}

long long inv(long long a) {
    return powmod(a, MOD - 2);
}

long long comb(long long n, long long k) {
    long long num = 1;
    long long den = 1;
    for (long long i = 1; i <= k; i++) {
        num = (num * (n - i + 1)) % MOD;
        den = (den * i) % MOD;
    }
    return (num * inv(den)) % MOD;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N, M, K;
        scanf("%lld %lld %lld", &N, &M, &K);
        long long ans = 0;
        for (long long i = 1; i <= K && i <= M; i++) {
            ans = (ans + comb(M, i) * powmod(i, N)) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

